    wrkPlCd = ds_vesselPortCountList.getCellData(i,"wrkPlCd").trim();

    if(odrKnd == "L1" && wrkPlCd != "") {
        ds_vesselPortCountListTempL1.setRowData(i, ds_vesselPortCountList.getRowData(i), false);
